def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        if item > capacity:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0
        if ratio == 1:
            score = 0
        elif ratio > 1:
            score = np.inf
        else:
            for power in range(1, 6):
                coef = (-1) ** power
                term = coef * (ratio ** power) / power
                score += term
            if ratio < 0.3:
                score *= 2
            elif ratio < 0.6:
                score *= 1.2
            else:
                score *= 0.8
            for j in range(-2, 3):
                idx = i + j
                if idx < 0 or idx >= n or j == 0:
                    continue
                neighbor = bins[idx]
                if neighbor <= 0:
                    continue
                diff_ratio = abs(capacity - neighbor) / neighbor
                proximity_factor = max(0.5, 1 - abs(j) * 0.2)
                score += diff_ratio * proximity_factor
            max_iter = int(capacity // item) if capacity >= item else 1
            for k in range(2, max_iter + 1):
                combined_ratio = (item * k) / capacity
                if combined_ratio <= 1:
                    score -= np.log(combined_ratio) / k
                else:
                    break
        priority = -score
        if priority < 0:
            priority = 0
        priorities[i] = priority
    finite_priorities = priorities[np.isfinite(priorities)]
    if len(finite_priorities) > 0:
        max_finite = np.max(finite_priorities)
        min_finite = np.min(finite_priorities)
    else:
        max_finite = 1
        min_finite = 0
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_finite * 2
        elif priorities[i] == 0:
            priorities[i] = min_finite * 0.5 if min_finite > 0 else 0.1
    return priorities
